import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`Oracle Academy Features DREAMER Project in New Blog Article`,date:`17.03.2026`,categories:[`blog`],published:!0},{title:i,date:a,categories:o,published:s}=r,c=t(`<p>Oracle Academy has published a new blog article highlighting the DREAMER project and its contribution to advancing project management education through international collaboration. Published on <strong>17 March 2026</strong> and authored by <strong>Danny Gooris, Regional Director of Oracle Academy, EMEA</strong>, the article presents DREAMER as an EU-funded initiative led by the <strong>Slovak University of Technology in Bratislava</strong> to support Ukraine’s recovery and strengthen project management education across Europe.</p> <p>The Oracle Academy blog emphasizes that DREAMER brings together universities from <strong>six countries</strong> and focuses on developing <strong>open-access, bilingual learning materials</strong> in project management, enriched with digital tools and real-world case studies. It also highlights the project’s collaborative approach, including hands-on learning with <strong>Oracle Primavera</strong>, knowledge exchange among partners, and its broader mission to prepare students, teachers, and professionals for reconstruction and sustainable development challenges.</p> <p>This recognition by Oracle Academy is an important milestone for the DREAMER consortium and a valuable contribution to the project’s international visibility. It reflects the relevance of DREAMER’s mission and confirms the importance of cross-border cooperation in building modern, accessible, and practice-oriented project management education.</p> <p><a href="https://blogs.oracle.com/academy/the-dreamer-eu-funded-international-initiative-advances-project-management-education-and-recovery-through-international-collaboration" rel="nofollow">The DREAMER EU-funded international initiative advances project management education and recovery through international collaboration | academy</a></p>`,1);function l(t){var r=c();e(6),n(t,r)}export{l as default,r as metadata};